/*\n  # Remove Wallet Address Foreign Key from Prize_Instantprizes\n\n  1. Changes\n    - Remove foreign key constraint on `winningWalletAddress` column\n    - This allows instant prizes to be pre-populated before winners are determined\n    - Winners will be assigned dynamically when users purchase tickets\n\n  2. Reasoning\n    - Instant win prizes need to be seeded into the database before any users win them\n    - The winning wallet address will be populated when a user wins the prize\n    - The competitionId foreign key remains to ensure prizes are linked to valid competitions\n*/\n\nALTER TABLE "Prize_Instantprizes" \nDROP CONSTRAINT IF EXISTS "Prize_Instantprizes_winningWalletAddress_fkey";
;
